from typing import List

class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        def backtrack(num, length):
            if length == n:
                result.append(num)
                return
            for i in range(10):
                if i != 0 or length == 1:
                    backtrack(num * 10 + i, length + 1)

        result = []
        for i in range(1, 10):
            backtrack(i, 1)
        return [num for num in result if len(str(num)) == n]
```

